import React from "react";
import "./Home.css";
import { MdLocalPhone } from "react-icons/md";

function Home() {
  return (
    <section className="home">
      <div className="overlay"> </div>
      <img src="/images/ch1.jpg" alt="wallpaper" className="imgWallpaper"></img>
      <div className="homeContent container">
        <div className="textDiv">
          <span className="smallText">Live Your Dream</span>
          <h1 className="homeTitle">In Search Of Incredible</h1>
        </div>

        <div className="homeFooterIcons flex">
          <div className="rightIcons">
            <MdLocalPhone className="icon" />
            <span>0933448412</span>
          </div>
          <div className="leftIcons"></div>
        </div>
      </div>
    </section>
  );
}

export default Home;
